(function () {
  var form = document.querySelector('[data-search-form]');
  var input = document.querySelector('[data-search-input]');
  var resultBox = document.querySelector('[data-search-results]');
  if (!form || !input || !resultBox) {
    return;
  }

  function fromUrl() {
    var params = new URLSearchParams(window.location.search);
    var q = params.get('q') || '';
    input.value = q;
    render(q);
  }

  function render(query) {
    var q = (query || '').trim().toLowerCase();
    var source = q ? MOVIE_ITEMS.filter(function (item) {
      return (item.title + ' ' + item.region + ' ' + item.type + ' ' + item.genre + ' ' + item.cat).toLowerCase().indexOf(q) !== -1;
    }) : MOVIE_ITEMS.slice(0, 36);
    resultBox.innerHTML = source.slice(0, 120).map(function (item) {
      return '<article class="search-result">'
        + '<a href="' + item.href + '"><img src="' + item.img + '" alt="' + escapeHtml(item.title) + '"></a>'
        + '<div><h2><a href="' + item.href + '">' + escapeHtml(item.title) + '</a></h2>'
        + '<p>' + escapeHtml([item.year, item.region, item.type, item.cat].filter(Boolean).join(' · ')) + '</p>'
        + '<p>' + escapeHtml(item.one) + '</p></div>'
        + '<a class="btn btn-primary" href="' + item.href + '">查看</a>'
        + '</article>';
    }).join('');
  }

  function escapeHtml(text) {
    return String(text || '').replace(/[&<>"']/g, function (ch) {
      return {'&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;'}[ch];
    });
  }

  form.addEventListener('submit', function (event) {
    event.preventDefault();
    var q = input.value.trim();
    var url = q ? 'search.html?q=' + encodeURIComponent(q) : 'search.html';
    history.replaceState(null, '', url);
    render(q);
  });

  input.addEventListener('input', function () {
    render(input.value);
  });

  fromUrl();
})();
